import React, { useContext, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { Dropdown, Container } from 'react-bootstrap'; 
// Importaciones de Contextos (Simuladas para previsualización)
import { AuthContext } from '../context/AuthContext';
import { CartContext } from '../context/CartContext';
import { SettingsContext } from '../context/SettingsContext'; 
// Componentes dependientes
import SearchBox from './SearchBox';
import HeaderSkeleton from './HeaderSkeleton'; 

const Header = () => {
  const navigate = useNavigate();
  // Simulación de datos y contextos (para que el Header pueda renderizarse)
  // En tu aplicación real, esto viene del useContext
  const user = { name: 'Super Administrador', permissions: ['access:admin_panel'] };
  const cartItems = [{ qty: 1 }];
  const settings = { siteName: 'TECNOTITLÁN', logoUrl: null, accentColor: '#00DC82' }; 
  const authLoading = false;
  const settingsLoading = false;
  
  // Hook para aplicar el color de acento
  useEffect(() => {
    if (settings?.accentColor) {
      document.documentElement.style.setProperty('--cta-color', settings.accentColor);
    }
  }, [settings]);

  const logoutHandler = () => { /* Simulado */ };
  const totalCartItems = cartItems.reduce((acc, item) => acc + item.qty, 0); 
  const canAccessAdminPanel = user?.permissions?.includes('access:admin_panel');
  const isLoading = authLoading || settingsLoading;

  if (isLoading) {
     return <HeaderSkeleton />;
  }
  
  const baseLinkClasses = "text-gray-300 no-underline hover:text-white transition-colors";
  
  return (
    // CRÍTICO: Usamos rounded-b-2xl para el redondeo inferior grande del Header, fusionándose con el Hero.
    // Usamos el color oscuro definido en index.css
    <header 
      className="w-full sticky top-0 z-50 transition-all duration-300 shadow-md rounded-b-2xl"
      style={{ backgroundColor: 'var(--brand-dark)' }} 
    >
      <Container className="py-3"> 
        {/* Usamos flex de Tailwind para mejor control sobre d-flex de Bootstrap */}
        <div className="flex justify-between items-center"> 
          
          {/* 1. Logo / Nombre del Sitio */}
          <Link 
            to="/" 
            // W-40 (160px) para dar espacio al logo
            className={`${baseLinkClasses} flex items-center h-full w-40 flex-shrink-0`}
            style={{ fontSize: '20px', fontWeight: 700 }}
          > 
            <span className="text-white whitespace-nowrap">
              {settings?.siteName || 'TECNOTITLÁN'}
            </span>
          </Link>

          {/* 2. Barra de búsqueda (Centrada y visible solo en Desktop) */}
          {/* CRÍTICO: mx-auto y w-1/2 max-w-lg centran el SearchBox en el espacio restante */}
          <div className="hidden lg:block w-1/2 max-w-lg mx-auto px-5">
            <SearchBox /> 
          </div>

          {/* 3. Navegación Derecha (Carrito y Usuario) */}
          {/* flex-shrink-0 para evitar que se encoja cuando el SearchBox crece */}
          <nav className="flex items-center gap-4 w-auto flex-shrink-0">
            
            {/* Icono del Carrito */}
            <Link 
              to="/cart" 
              className={`relative ${baseLinkClasses} flex items-center`}
            >
              <i className="fas fa-shopping-cart text-xl"></i>
              <span className="hidden md:inline ms-2 font-medium">Carrito</span>
              {totalCartItems > 0 && (
                <span className="absolute -top-2 -right-2 bg-red-600 text-white text-[10px] font-bold px-1.5 py-0.5 rounded-full shadow-sm">
                  {totalCartItems}
                </span>
              )}
            </Link>

            {/* Menú de Usuario */}
            <Dropdown align="end">
              <Dropdown.Toggle 
                as="a" 
                className={`${baseLinkClasses} font-medium gap-2 cursor-pointer text-white no-underline flex items-center`} 
              >
                <i className="fas fa-user"></i> 
                <span className="hidden md:inline ms-2 font-medium">{user.name || 'Usuario'}</span>
              </Dropdown.Toggle>

              <Dropdown.Menu className="shadow-xl border-0 rounded-lg mt-2 p-1 bg-white">
                <Dropdown.Item as={Link} to="/profile" className="rounded py-2">Perfil</Dropdown.Item>
                {canAccessAdminPanel && (
                  <Dropdown.Item as={Link} to="/admin/dashboard" className="rounded py-2">Panel Admin</Dropdown.Item>
                )}
                <Dropdown.Divider className="my-1" />
                <Dropdown.Item onClick={logoutHandler} className="text-red-600 rounded py-2">Cerrar Sesión</Dropdown.Item>
              </Dropdown.Menu>
            </Dropdown>
          </nav>
        </div>
        
        {/* Barra de búsqueda (Solo Móvil - Se extiende en su propia fila) */}
        <div className="lg:hidden mt-3">
          <SearchBox />
        </div>
      </Container>
    </header>
  );
};

// SIMULACIÓN DE CONTEXTOS PARA QUE NO FALLE LA CARGA
const MockAuthContext = { userInfo: { name: 'Super Administrador' }, logout: () => {}, loading: false };
const MockCartContext = { cartItems: [{ qty: 1 }], isItemJustAdded: false };
const MockSettingsContext = { settings: { siteName: 'TECNOTITLÁN', accentColor: '#00DC82' }, loading: false };

// Este componente solo se usa para previsualización con datos mock.
const HeaderPreview = () => (
    <AuthContext.Provider value={MockAuthContext}>
        <CartContext.Provider value={MockCartContext}>
            <SettingsContext.Provider value={MockSettingsContext}>
                <Header />
            </SettingsContext.Provider>
        </CartContext.Provider>
    </AuthContext.Provider>
);

export default HeaderPreview;
